#include <stdio.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        unsigned int N; scanf("%u", &N);
        int cnt=0; unsigned int x=N;
        while(x){ cnt += x & 1u; x >>= 1; }
        printf("%d\n", cnt-1);
    }
    return 0;
}

